INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24001, 2, "2030/12/17 14:59:59", "アヤネ", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 102301, 0.0, "2020/07/31 12:00:00", 2, 24, 401, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24002, 1, "2030/12/17 14:59:59", "アヤネ", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 102301, 0.0, "2020/07/31 12:00:00", 2, 24, 402, 0.0, 2.21);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24003, 2, "2030/12/17 14:59:59", "アヤネ", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 102301, 0.0, "2020/07/31 12:00:00", 2, 24, 403, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24004, 2, "2030/12/17 14:59:59", "アサヒ", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 192201, 0.0, "2020/07/31 12:00:00", 1, 24, 701, 0.0, 1.99);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24005, 1, "2030/12/17 14:59:59", "アサヒ", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 192201, 0.0, "2020/07/31 12:00:00", 2, 24, 702, 0.0, 2.21);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24006, 2, "2030/12/17 14:59:59", "アサヒ", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 192201, 0.0, "2020/07/31 12:00:00", 1, 24, 703, 0.0, 3.33);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24007, 2, "2030/12/17 14:59:59", "部員３", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 192301, 0.0, "2020/07/31 12:00:00", 2, 24, 801, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24008, 1, "2030/12/17 14:59:59", "部員３", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 192301, 0.0, "2020/07/31 12:00:00", 2, 24, 802, 0.0, 2.68);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24009, 2, "2030/12/17 14:59:59", "部員３", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 192301, 0.0, "2020/07/31 12:00:00", 2, 24, 803, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24010, 1, "2030/12/17 14:59:59", "", "やった！", 192501, 0.0, "2020/07/31 12:00:00", 1, 24, 501, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24011, 1, "2030/12/17 14:59:59", "", "勝ったよ！", 192501, 0.0, "2020/07/31 12:00:00", 1, 24, 502, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24012, 1, "2030/12/17 14:59:59", "", "いい調子！", 192501, 0.0, "2020/07/31 12:00:00", 1, 24, 503, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24013, 6, "2030/12/17 14:59:59", "ミサト", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 111, 0.0, 5.33);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24014, 1, "2030/12/17 14:59:59", "ミサト", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 112, 0.0, 6.85);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24015, 1, "2030/12/17 14:59:59", "ミサト", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 113, 0.0, 3.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24016, 1, "2030/12/17 14:59:59", "ダイチ", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 192401, 0.0, "2020/07/31 12:00:00", 2, 24, 611, 0.0, 6.11);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24017, 1, "2030/12/17 14:59:59", "ダイチ", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 192401, 0.0, "2020/07/31 12:00:00", 2, 24, 612, 0.0, 6.75);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24018, 2, "2030/12/17 14:59:59", "ダイチ", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 192401, 0.0, "2020/07/31 12:00:00", 2, 24, 613, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24019, 2, "2030/12/17 14:59:59", "ハツネ", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 113401, 0.0, "2020/07/31 12:00:00", 1, 24, 211, 0.0, 4.52);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24020, 2, "2030/12/17 14:59:59", "ハツネ", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 113401, 0.0, "2020/07/31 12:00:00", 1, 24, 212, 0.0, 3.89);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24021, 1, "2030/12/17 14:59:59", "ハツネ", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 113401, 0.0, "2020/07/31 12:00:00", 2, 24, 213, 0.0, 13.49);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24022, 1, "2030/12/17 14:59:59", "カヤ", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 106501, 0.0, "2020/07/31 12:00:00", 2, 24, 311, 0.0, 3.17);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24023, 1, "2030/12/17 14:59:59", "カヤ", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 106501, 0.0, "2020/07/31 12:00:00", 2, 24, 312, 0.0, 4.42);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24024, 6, "2030/12/17 14:59:59", "カヤ", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 106501, 0.0, "2020/07/31 12:00:00", 1, 24, 313, 0.0, 2.89);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24025, 4, "2030/12/17 14:59:59", "アヤネ", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 102301, 0.0, "2020/07/31 12:00:00", 3, 24, 421, 0.0, 3.71);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24026, 2, "2030/12/17 14:59:59", "アサヒ", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 192201, 0.0, "2020/07/31 12:00:00", 1, 24, 721, 0.0, 5.1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24027, 1, "2030/12/17 14:59:59", "部員３", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 192301, 0.0, "2020/07/31 12:00:00", 3, 24, 821, 0.0, 4.34);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24028, 1, "2030/12/17 14:59:59", "", "いい勝負だったよ\nまたやろうね", 192501, 0.0, "2020/07/31 12:00:00", 1, 24, 521, 0.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24029, 1, "2030/12/17 14:59:59", "ミサト", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 101, -360.0, 5.62);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24030, 1, "2030/12/17 14:59:59", "ミサト", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 102, -360.0, 9.58);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24031, 2, "2030/12/17 14:59:59", "ミサト", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 103, -360.0, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24032, 2, "2030/12/17 14:59:59", "ミサト", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 113501, 0.0, "2020/07/31 12:00:00", 1, 24, 104, -360.0, 9.13);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24033, 1, "2030/12/17 14:59:59", "ミサト", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 113501, 0.0, "2020/07/31 12:00:00", 2, 24, 105, -360.0, 8.27);
